#!/usr/bin/env node
/**
 * generate-ecosystem-manifest.ts
 *
 * Scans the monorepo at build time and produces a JSON manifest of:
 *   - Live sites (apps with wrangler.toml or known domains)
 *   - Open-source projects (open-source/*)
 *   - MCP servers (apps/*-mcp)
 *   - Hugging Face spaces (apps/*-space)
 *   - Platform targets (known app directories)
 *   - Ebooks (docs/ebooks/*)
 *
 * Output: client/generated/ecosystem-manifest.json
 *
 * Zero maintenance: add a new app/package/ebook and it appears automatically.
 */

import { readdirSync, readFileSync, existsSync, mkdirSync } from 'fs';
import { writeFileSync } from 'fs';
import { resolve, join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const ROOT = resolve(__dirname, '../../../../');
const OUT_DIR = resolve(__dirname, '../client/generated');
const OUT_FILE = join(OUT_DIR, 'ecosystem-manifest.json');

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function readJson(path: string): Record<string, unknown> | null {
  try {
    return JSON.parse(readFileSync(path, 'utf-8'));
  } catch {
    return null;
  }
}

function readFrontmatter(
  path: string
): Record<string, string | string[]> | null {
  try {
    const content = readFileSync(path, 'utf-8');
    const match = content.match(/^---\n([\s\S]*?)\n---/);
    if (!match) return null;
    const fm: Record<string, string | string[]> = {};
    for (const line of match[1].split('\n')) {
      const [key, ...rest] = line.split(':');
      if (key && rest.length) {
        fm[key.trim()] = rest.join(':').trim();
      }
    }
    return fm;
  } catch {
    return null;
  }
}

function listDirs(base: string): string[] {
  try {
    return readdirSync(base, { withFileTypes: true })
      .filter((d) => d.isDirectory())
      .map((d) => d.name)
      .sort();
  } catch {
    return [];
  }
}

function extractDescription(dir: string, name: string): string {
  // Try package.json description first
  const pkg = readJson(join(dir, 'package.json'));
  if (pkg?.description && typeof pkg.description === 'string') {
    return pkg.description;
  }

  // Try README first line after heading
  const readmePath = join(dir, 'README.md');
  if (existsSync(readmePath)) {
    try {
      const lines = readFileSync(readmePath, 'utf-8').split('\n');
      for (const line of lines) {
        const trimmed = line.trim();
        if (trimmed && !trimmed.startsWith('#') && !trimmed.startsWith('<!--')) {
          return trimmed.slice(0, 200);
        }
      }
    } catch {
      // ignore
    }
  }

  return name;
}

// ---------------------------------------------------------------------------
// Known domain mappings (stable, rarely changes)
// ---------------------------------------------------------------------------

const KNOWN_DOMAINS: Record<string, string> = {
  'docs-app': 'docs.forkjoin.ai',
  'mcp-superserver': 'mcp.forkjoin.ai',
  'polyglot-scanner': 'mudras.us',
  'voids-fyi': 'voids.fyi',
  'stars-fish': 'stars.fish',
  'storms-watch': 'storms.watch',
  'hexwar-app': 'ucan.guide',
  'gnosis-church': 'gnosis.church',
  'fractal-note': 'note.yoga',
  'memo-yoga': 'memo.yoga',
  'fractal-iam': 'card.yoga',
  'them-yoga': 'them.yoga',
  'storybook-app': 'storybook.forkjoin.ai',
  'aeon-foundation': 'aeonflux.dev',
  'forgo-cloud-worker': 'forgo.cloud',
  'wallington-lab': 'wallington-lab',
  'forkjoin-app': 'forkjoin.ai',
  'affectively-app': 'affectively.ai',
  'edgework-app': 'edgework.ai',
};

const PLATFORM_APPS: Record<string, { runtime: string }> = {
  'desktop-app': { runtime: 'Tauri' },
  'mobile-app': { runtime: 'React Native' },
  'browser-extension': { runtime: 'Manifest V3' },
  cli: { runtime: 'Node 22+' },
  'aeon-cli': { runtime: 'Node 22+' },
};

const PLATFORM_OSS: Record<string, { runtime: string }> = {
  'vscode-gnosis': { runtime: 'VS Code Extension' },
  zedge: { runtime: 'Zed Extension' },
};

// ---------------------------------------------------------------------------
// Collectors
// ---------------------------------------------------------------------------

interface LiveSite {
  name: string;
  domain: string;
  description: string;
}

interface OSSProject {
  name: string;
  repo: string;
  description: string;
  tags: string[];
}

interface MCPServer {
  name: string;
  slug: string;
  description: string;
}

interface HFSpace {
  name: string;
  slug: string;
  description: string;
}

interface PlatformTarget {
  name: string;
  runtime: string;
  description: string;
  repo: string;
}

interface EbookCategory {
  name: string;
  volumes: string;
  count: number;
  titles: string[];
}

interface EcosystemManifest {
  generatedAt: string;
  liveSites: LiveSite[];
  openSource: OSSProject[];
  mcpServers: MCPServer[];
  researchSpaces: HFSpace[];
  platforms: PlatformTarget[];
  ebookCategories: EbookCategory[];
  counts: {
    liveSites: number;
    openSource: number;
    mcpServers: number;
    researchSpaces: number;
    platforms: number;
    ebooks: number;
  };
}

// -- Live Sites --
function collectLiveSites(): LiveSite[] {
  const appsDir = join(ROOT, 'apps');
  const sites: LiveSite[] = [];

  for (const [appName, domain] of Object.entries(KNOWN_DOMAINS)) {
    const appDir = join(appsDir, appName);
    if (!existsSync(appDir)) continue;

    const description = extractDescription(appDir, appName);
    const name = appName
      .replace(/-app$/, '')
      .replace(/-mcp$/, '')
      .replace(/-worker$/, '')
      .split('-')
      .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
      .join(' ');

    sites.push({ name, domain, description });
  }

  return sites;
}

// -- Open Source --
function collectOpenSource(): OSSProject[] {
  const ossDir = join(ROOT, 'open-source');
  const dirs = listDirs(ossDir);
  const projects: OSSProject[] = [];

  for (const dir of dirs) {
    if (dir === 'README.md') continue;
    const fullDir = join(ossDir, dir);
    const description = extractDescription(fullDir, dir);

    // Derive tags from directory name patterns
    const tags: string[] = [];
    if (dir.startsWith('aeon-')) tags.push('aeon');
    if (dir.startsWith('wasm-')) tags.push('wasm');
    if (dir.includes('gnosis') || dir === 'raect') tags.push('gnosis');
    if (
      dir.includes('buleyean') ||
      dir === 'maybe' ||
      dir === 'aunt-sandy'
    )
      tags.push('research');
    if (dir.includes('dash') || dir.includes('relay')) tags.push('data');
    if (dir.includes('auth') || dir.includes('zk')) tags.push('security');

    const name = dir
      .split('-')
      .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
      .join(' ');

    projects.push({ name, repo: dir, description, tags });
  }

  return projects;
}

// -- MCP Servers --
function collectMCPServers(): MCPServer[] {
  const appsDir = join(ROOT, 'apps');
  const dirs = listDirs(appsDir);
  const servers: MCPServer[] = [];

  for (const dir of dirs) {
    if (!dir.endsWith('-mcp')) continue;
    const slug = dir.replace(/-mcp$/, '');
    const fullDir = join(appsDir, dir);
    const description = extractDescription(fullDir, dir);

    const name = slug
      .split('-')
      .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
      .join(' ');

    servers.push({ name, slug, description });
  }

  return servers;
}

// -- HF Spaces --
function collectSpaces(): HFSpace[] {
  const appsDir = join(ROOT, 'apps');
  const dirs = listDirs(appsDir);
  const spaces: HFSpace[] = [];

  for (const dir of dirs) {
    if (!dir.endsWith('-space')) continue;
    const slug = dir.replace(/-space$/, '');
    const fullDir = join(appsDir, dir);
    const description = extractDescription(fullDir, dir);

    const name = slug
      .split('-')
      .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
      .join(' ');

    spaces.push({ name, slug, description });
  }

  return spaces;
}

// -- Platforms --
function collectPlatforms(): PlatformTarget[] {
  const platforms: PlatformTarget[] = [];

  for (const [appName, meta] of Object.entries(PLATFORM_APPS)) {
    const appDir = join(ROOT, 'apps', appName);
    if (!existsSync(appDir)) continue;
    const description = extractDescription(appDir, appName);
    const name = appName
      .replace(/-app$/, '')
      .split('-')
      .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
      .join(' ');
    platforms.push({ name, runtime: meta.runtime, description, repo: appName });
  }

  for (const [ossName, meta] of Object.entries(PLATFORM_OSS)) {
    const ossDir = join(ROOT, 'open-source', ossName);
    if (!existsSync(ossDir)) continue;
    const description = extractDescription(ossDir, ossName);
    const name = ossName
      .split('-')
      .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
      .join(' ');
    platforms.push({ name, runtime: meta.runtime, description, repo: ossName });
  }

  return platforms;
}

// -- Ebooks --
function collectEbooks(): { categories: EbookCategory[]; total: number } {
  const ebooksDir = join(ROOT, 'docs', 'ebooks');
  const dirs = listDirs(ebooksDir).filter((d) => /^\d+/.test(d));

  // Sort by volume number
  dirs.sort((a, b) => {
    const numA = parseInt(a.split('-')[0], 10);
    const numB = parseInt(b.split('-')[0], 10);
    return numA - numB;
  });

  // Group into ranges
  const ranges: { min: number; max: number; label: string; titles: string[] }[] =
    [
      { min: 1, max: 10, label: 'Foundations', titles: [] },
      { min: 11, max: 25, label: 'Edge Inference & AI', titles: [] },
      { min: 26, max: 41, label: 'Design Patterns', titles: [] },
      { min: 42, max: 70, label: 'Model Cards', titles: [] },
      { min: 71, max: 89, label: 'Agents & Games', titles: [] },
      { min: 90, max: 121, label: 'App Guides', titles: [] },
      { min: 122, max: 152, label: 'Advanced Theory', titles: [] },
      { min: 153, max: 999, label: 'Gnosis & Formal Methods', titles: [] },
    ];

  for (const dir of dirs) {
    const num = parseInt(dir.split('-')[0], 10);
    const title = dir
      .replace(/^\d+-/, '')
      .replace(/-/g, ' ')
      .replace(/\b\w/g, (c) => c.toUpperCase());

    for (const range of ranges) {
      if (num >= range.min && num <= range.max) {
        range.titles.push(title);
        break;
      }
    }
  }

  const categories = ranges
    .filter((r) => r.titles.length > 0)
    .map((r) => ({
      name: r.label,
      volumes: `${r.min}--${Math.min(r.max, parseInt(dirs[dirs.length - 1]?.split('-')[0] ?? '0', 10))}`,
      count: r.titles.length,
      titles: r.titles,
    }));

  return { categories, total: dirs.length };
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

function main() {
  const liveSites = collectLiveSites();
  const openSource = collectOpenSource();
  const mcpServers = collectMCPServers();
  const researchSpaces = collectSpaces();
  const platforms = collectPlatforms();
  const { categories: ebookCategories, total: ebookTotal } = collectEbooks();

  const manifest: EcosystemManifest = {
    generatedAt: new Date().toISOString(),
    liveSites,
    openSource,
    mcpServers,
    researchSpaces,
    platforms,
    ebookCategories,
    counts: {
      liveSites: liveSites.length,
      openSource: openSource.length,
      mcpServers: mcpServers.length,
      researchSpaces: researchSpaces.length,
      platforms: platforms.length,
      ebooks: ebookTotal,
    },
  };

  if (!existsSync(OUT_DIR)) {
    mkdirSync(OUT_DIR, { recursive: true });
  }

  writeFileSync(OUT_FILE, JSON.stringify(manifest, null, 2));

  console.log(`Ecosystem manifest generated: ${OUT_FILE}`);
  console.log(`  Live sites:      ${liveSites.length}`);
  console.log(`  Open-source:     ${openSource.length}`);
  console.log(`  MCP servers:     ${mcpServers.length}`);
  console.log(`  HF spaces:       ${researchSpaces.length}`);
  console.log(`  Platforms:       ${platforms.length}`);
  console.log(`  Ebook volumes:   ${ebookTotal}`);
  console.log(`  Ebook categories: ${ebookCategories.length}`);
}

main();
